#include <stdio.h>
#include <stdlib.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N,Q; scanf("%d %d", &N, &Q);
        int *A = (int*)malloc(N*sizeof(int));
        int cnt[31]={0};
        for(int i=0;i<N;i++){
            scanf("%d", &A[i]);
            for(int b=0;b<31;b++) if(A[i]>>b & 1) cnt[b]++;
        }
        long long ans=0;
        for(int b=0;b<31;b++) if(cnt[b]) ans |= 1LL<<b;
        printf("%lld\n", ans);
        while(Q--){
            int X, V; scanf("%d %d", &X, &V);
            --X; // to 0‑based
            int old = A[X];
            if(old!=V){
                for(int b=0;b<31;b++){
                    if(old>>b & 1) cnt[b]--;
                    if(V>>b & 1) cnt[b]++;
                }
                A[X]=V;
            }
            ans=0;
            for(int b=0;b<31;b++) if(cnt[b]) ans |= 1LL<<b;
            printf("%lld\n", ans);
        }
        free(A);
    }
    return 0;
}

