import java.io.*;
import java.util.*;

public class Main {
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in){ this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return val * sign;
        }
    }
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        StringBuilder out = new StringBuilder();
        int T = fs.nextInt();
        while (T-- > 0) {
            int N = fs.nextInt();
            int Q = fs.nextInt();
            int[] A = new int[N];
            int[] cnt = new int[31];
            for (int i = 0; i < N; i++) {
                A[i] = fs.nextInt();
                for (int b = 0; b < 31; b++) if ((A[i] >> b & 1) == 1) cnt[b]++;
            }
            out.append(compute(cnt)).append('\n');
            while (Q-- > 0) {
                int X = fs.nextInt() - 1;
                int V = fs.nextInt();
                int old = A[X];
                if (old != V) {
                    for (int b = 0; b < 31; b++) {
                        if ((old >> b & 1) == 1) cnt[b]--;
                        if ((V >> b & 1) == 1) cnt[b]++;
                    }
                    A[X] = V;
                }
                out.append(compute(cnt)).append('\n');
            }
        }
        System.out.print(out.toString());
    }
    private static int compute(int[] cnt) {
        int res = 0;
        for (int b = 0; b < 31; b++) if (cnt[b] > 0) res |= (1 << b);
        return res;
    }
}

