import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    t = int(next(it))
    out_lines = []
    for _ in range(t):
        n = int(next(it)); q = int(next(it))
        A = [int(next(it)) for _ in range(n)]
        cnt = [0]*31
        for val in A:
            for b in range(31):
                if val>>b & 1:
                    cnt[b] += 1
        def current_or():
            res = 0
            for b in range(31):
                if cnt[b]:
                    res |= 1<<b
            return res
        out_lines.append(str(current_or()))
        for _ in range(q):
            x = int(next(it)) - 1
            v = int(next(it))
            old = A[x]
            if old != v:
                for b in range(31):
                    if old>>b & 1:
                        cnt[b] -= 1
                    if v>>b & 1:
                        cnt[b] += 1
                A[x] = v
            out_lines.append(str(current_or()))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

